% =========================================================================
% AI ACKNOWLEDGMENT: This code was generated by Claude (Anthropic) with
% inputs and direction from Peter Martin.
%
% Imager_CNN_RegLOPO.m  --  Leave-One-POSITION-Out (x,y) REGRESSION CNN
%
% A DIFFERENT cross-validation from Imager_CNN_RegLOSO.m.  Instead of holding
% out a whole recording SESSION, this holds out a GRID POSITION the model has
% never seen a signature for, and asks it to predict that position's (x,y).
% This tests SPATIAL INTERPOLATION of the field -- something the classifiers
% structurally could not do (a zero-example class can never be predicted).
%
% TWO MODES  (env LOPO_MODE):
%   insession : train + test within ONE session, rotated over sessions.
%               Session drift is removed -> pure interpolation question.
%   pooled    : hold the position out of EVERY session; train on all remaining
%               positions from all sessions.  Tests interpolation AND
%               cross-session generalization at once (closest to deployment).
%
% TWO GRANULARITIES  (env LOPO_UNIT):
%   subpos : hold out ONE sub-position (its 3 cell-mates ~0.75in away stay in
%            training) -> gentle interpolation.
%   cell   : hold out the WHOLE cell (all 4 sub-positions) -> forces bridging
%            a full inch-plus gap -> strong test of learned spatial structure.
%
% This is DISTINCT from LOSO and the two modes/granularities are DISTINCT from
% each other, in both the console banner and the output filenames:
%     cnn_reglopo_<mode>_<unit>_<setup>_<setlabel>_<input>.json
% (LOSO writes cnn_regloso_*, so the two families never collide.)
%
% Same data pipeline as RegLOSO: complex baseline subtraction (v2, no session-
% mean), raw|physics|tdr features, per-session z-score, conv trunk + fc(2) +
% regressionLayer.  Error DISTANCE only (no snapping).  Targets = canonical
% grid (x,y) + photo overrides (CNN_LOSO_ADJUST_KEY).
%
% ENV VARS: CNN_LOSO_PARENT, CNN_LOSO_SESSIONS, CNN_LOSO_PORT_REMAP,
%   CNN_LOSO_ADJUST_KEY, CNN_LOSO_INPUT (default raw), CNN_LOSO_MEANSUB,
%   CNN_LOSO_EPOCHS (default 40 here -- LOPO trains many folds),
%   CNN_LOSO_SETLABEL, LOPO_MODE (insession|pooled), LOPO_UNIT (subpos|cell).
% =========================================================================

clear; clc; close all;

fprintf('==============================================================\n');
fprintf('  Imager CNN  --  Leave-One-POSITION-Out (x,y) REGRESSION\n');
fprintf('==============================================================\n\n');

%% CONFIG
cfg.LR = 1e-3; cfg.BatchSize = 16; cfg.Epochs = 40;
cfg.Conv1 = 32; cfg.Conv2 = 32; cfg.FC1 = 64; cfg.Dropout = 0.3;
cfg.LRDropFactor = 0.5; cfg.LRDropPeriod = 30; cfg.showPlots = false;
if ~isempty(getenv('CNN_LOSO_EPOCHS'))
    cfg.Epochs = str2double(getenv('CNN_LOSO_EPOCHS'));
    fprintf('[override] Epochs = %d\n', cfg.Epochs);
end
rng(42);
if usejava('desktop'), figVis = 'on'; else, figVis = 'off'; end

LOADER_DIR = 'C:\Users\peter\Desktop\EM Imaging\Imager Program';
if exist(fullfile(LOADER_DIR, 'loadHunterVnaFolder.m'), 'file'), addpath(LOADER_DIR); end
thisDir = fileparts(mfilename('fullpath')); if isempty(thisDir), thisDir = pwd; end
resultsDir = fullfile(fileparts(thisDir), 'results');
if ~isfolder(resultsDir), mkdir(resultsDir); end

% ---- LOPO mode + granularity ----
lopoMode = lower(strtrim(getenv('LOPO_MODE'))); if isempty(lopoMode), lopoMode = 'pooled'; end
lopoUnit = lower(strtrim(getenv('LOPO_UNIT'))); if isempty(lopoUnit), lopoUnit = 'cell'; end
if ~ismember(lopoMode, {'insession', 'pooled'}), error('LOPO_MODE must be insession|pooled'); end
if ~ismember(lopoUnit, {'subpos', 'cell'}), error('LOPO_UNIT must be subpos|cell'); end
fprintf('LOPO mode = %s   granularity = %s\n', upper(lopoMode), upper(lopoUnit));

% ---- Experiment 1: mixup augmentation (off unless MIXUP_ALPHA>0) ----
% Offline mixup for regression: append synthetic TRAIN samples that are convex
% blends of random training pairs, with matching convex-blended (x,y) targets.
% Teaches the signal->coordinate map to be smooth -> better interpolation to
% never-seen positions. Applied to TRAIN only, never the held-out cell.
mixAlpha = str2double(getenv('MIXUP_ALPHA')); if isnan(mixAlpha), mixAlpha = 0; end
mixRatio = str2double(getenv('MIXUP_RATIO')); if isnan(mixRatio), mixRatio = 1.0; end
if mixAlpha > 0
    fprintf('MIXUP ON: alpha=%.2f  ratio=%.2f  (blend train pairs + their xy)\n', mixAlpha, mixRatio);
end

% ---- Experiment 2: position-disjoint validation (off unless POSVAL_FRAC>0) ----
% Carve a fraction of the TRAIN positions out as a validation set (all their
% trials, none in training) and keep the network with the best validation loss
% (OutputNetwork='best-validation'). Selects for generalization to UNSEEN
% positions rather than long training on memorized ones.
posValFrac = str2double(getenv('POSVAL_FRAC')); if isnan(posValFrac), posValFrac = 0; end
if posValFrac > 0
    fprintf('POSVAL ON: frac=%.2f of train positions held out for best-net selection\n', posValFrac);
end

% ---- Experiment 3: structured (heatmap) output (HEAD_MODE=heatmap) ----
% Instead of fc(2) regressing bare (x,y), output a softmax over a grid of
% coordinate anchors, trained against a Gaussian blob centred at the true xy,
% and read out the prediction as the distribution's centroid. Neighbouring
% positions share output support -> smoother interpolation. Uses only built-in
% layers (fc -> softmax -> regression on the soft target).
headMode = lower(strtrim(getenv('HEAD_MODE'))); if isempty(headMode), headMode = 'xy'; end
if ~ismember(headMode, {'xy', 'heatmap'}), error('HEAD_MODE must be xy|heatmap'); end
hmSigma = str2double(getenv('HEATMAP_SIGMA')); if isnan(hmSigma), hmSigma = 0.6; end
if strcmp(headMode, 'heatmap')
    fprintf('HEAD=heatmap  sigma=%.2f in  (soft-argmax centroid readout)\n', hmSigma);
end

%% 1. DATA
defaultParent = ['C:\Users\peter\Desktop\EM Imaging\BreastPhantom\HunterVNA\' ...
                 'DataMeasurements\Sam Antennas\MediumAntenna\Separated\June18'];
if ~isfolder(defaultParent), defaultParent = pwd; end
if ~isempty(getenv('CNN_LOSO_PARENT'))
    parentDir = getenv('CNN_LOSO_PARENT');
    fprintf('[override] parent folder = %s\n', parentDir);
else
    parentDir = uigetdir(defaultParent, 'Select parent folder (holds session subfolders)');
    if isequal(parentDir, 0), fprintf('Cancelled.\n'); return; end
end

[sessions, sessNames] = loadAllSessions(parentDir);
nSess = numel(sessions);
if nSess < 1, error('No sessions found in %s', parentDir); end
if strcmp(lopoMode, 'pooled') && nSess < 2
    fprintf('[note] pooled LOPO with 1 session == insession LOPO.\n');
end
fprintf('\nLoaded %d sessions:\n', nSess);
for s = 1:nSess
    fprintf('   [%d] %-45s  %d positions, %d trials\n', s, sessNames{s}, ...
        numel(sessions{s}.posLabels), sessions{s}.trialCount);
end
[~, setupName] = fileparts(parentDir); if isempty(setupName), setupName = 'setup'; end
meanSub = strcmp(strtrim(getenv('CNN_LOSO_MEANSUB')), '1');
if meanSub, preproc = 'v1_session_mean'; else, preproc = 'v2_no_session_mean'; end
