if strcmp(headMode, 'heatmap'), setLabel = [setLabel sprintf('-heatmap%s', strrep(num2str(hmSigma), '.', 'p'))]; end

%% 2. ANTENNAS + TARGETS
ports = 1:4; antennaMode = 'all';   % first pass: full 4-antenna array only
[selRows, sparamNames, sparamPairs] = antennaRows(ports, false); %#ok<ASGLU>
inputMode = lower(strtrim(getenv('CNN_LOSO_INPUT'))); if isempty(inputMode), inputMode = 'raw'; end
N_TDR_BINS = 64;

adjKey = strtrim(getenv('CNN_LOSO_ADJUST_KEY'));
ADJ_JSON = ['C:\Users\peter\Desktop\EM Imaging\Research Paper\github_repo\' ...
            'detectable_change\A3_hunter\position_adjustments.json'];
adjMap = containers.Map('KeyType', 'char', 'ValueType', 'any');
if ~isempty(adjKey) && ~strcmpi(adjKey, 'none')
    J = jsondecode(fileread(ADJ_JSON));
    if ~isfield(J, adjKey), error('adjust key "%s" not in %s', adjKey, ADJ_JSON); end
    A = J.(adjKey); fn = fieldnames(A);
    for ii = 1:numel(fn), v = A.(fn{ii}); adjMap(fn{ii}) = double(v(:)'); end
    fprintf('Target adjustments [%s]: %d positions photo-corrected\n', adjKey, adjMap.Count);
else
    adjKey = 'none';
end

tag = sprintf('%s_%s_%s_%s_%s', lopoMode, lopoUnit, ...
              matlab.lang.makeValidName(setupName), setLabel, inputMode);
fprintf('Input=%s  antenna=ALL(16 S-params)  preproc=%s  adjust=%s\n', inputMode, preproc, adjKey);

%% 3. BUILD PER-SESSION TENSORS
fprintf('\n--- Building per-session samples ---\n');
built = cell(nSess, 1); posSetPerSess = cell(nSess, 1);
for s = 1:nSess
    built{s} = buildSession(sessions{s}, sparamPairs, inputMode, N_TDR_BINS, meanSub);
    posSetPerSess{s} = unique(built{s}.posLabel);
    fprintf('   session %d: %d samples across %d positions\n', ...
        s, numel(built{s}.posLabel), numel(posSetPerSess{s}));
end
validPos = posSetPerSess{1};
for s = 2:nSess, validPos = intersect(validPos, posSetPerSess{s}); end
validPos = sort(validPos); nPos = numel(validPos);
if nPos < 3, error('Need >=3 common positions for LOPO.'); end

validXY = zeros(nPos, 2);
for p = 1:nPos, validXY(p, :) = labelToXY(validPos{p}, adjMap); end
xyOf = containers.Map(validPos, num2cell(validXY, 2)');

% heatmap anchor grid (only used if headMode=heatmap): regular 0.4-in lattice
% covering the target extent + margin, so the centroid readout can reach every
% true position.
axStep = 0.4; axPad = 0.6;
ax = (min(validXY(:,1)) - axPad) : axStep : (max(validXY(:,1)) + axPad);
ay = (min(validXY(:,2)) - axPad) : axStep : (max(validXY(:,2)) + axPad);
[AX, AY] = meshgrid(ax, ay);
anchors = [AX(:), AY(:)];
if strcmp(headMode, 'heatmap')
    fprintf('Heatmap anchors: %d (%.1f-in grid over [%.1f,%.1f]x[%.1f,%.1f])\n', ...
        size(anchors,1), axStep, ax(1), ax(end), ay(1), ay(end));
end
nearInsertMap = containers.Map(validPos, num2cell(arrayfun(@(p) isKey(adjMap, validPos{p}), 1:nPos)));

% ---- define held-out units ----
if strcmp(lopoUnit, 'subpos')
    units = cellfun(@(L) {L}, validPos, 'uni', 0);      % one label each
    unitName = validPos;
else  % cell: group by RxCy
    ckey = cellfun(@(L) regexprep(L, 'P\d+$', ''), validPos, 'uni', 0);
    unitName = unique(ckey, 'stable');
    units = cell(numel(unitName), 1);
    for i = 1:numel(unitName), units{i} = validPos(strcmp(ckey, unitName{i})); end
end
nUnits = numel(units);
fprintf('Common positions: %d   held-out units (%s): %d\n', nPos, lopoUnit, nUnits);

numSParamRows = size(built{1}.X, 1); numFreqPoints = size(built{1}.X, 2);
if gpuDeviceCount > 0, execEnv = 'gpu'; else, execEnv = 'cpu'; end
fprintf('CNN input: %d x %d  (input=%s)   env=%s\n', numSParamRows, numFreqPoints, inputMode, execEnv);

%% 4. LOPO LOOP  -> collect one record per held-out position (per context)
HALF = 0.5;
rec = struct('label', {}, 'sess', {}, 'err', {}, 'spread', {}, 'near', {});
nFoldTotal = 0; tAll = tic;

if strcmp(lopoMode, 'pooled')
    % pool all valid samples across sessions once
    Xp = []; yp = {};
    for s = 1:nSess
        keep = ismember(built{s}.posLabel, validPos);
        Xp = cat(4, Xp, built{s}.X(:, :, :, keep));
        yp = [yp; built{s}.posLabel(keep)]; %#ok<AGROW>
    end
    for u = 1:nUnits
        t0 = tic;
        teMask = ismember(yp, units{u}); trMask = ~teMask;
        yTr = yp(trMask);
        TTr = labelsToXY(yTr, adjMap);
        [Xt0, Tt0, Xv0, Tv0] = posDisjointSplit(Xp(:, :, :, trMask), TTr, yTr, posValFrac);
        [Xtr_a, Ttr_a] = maybeMixup(Xt0, Tt0, mixAlpha, mixRatio);
        predTe = fitPredictFold(Xtr_a, Ttr_a, Xp(:, :, :, teMask), Xv0, Tv0, ...
                                headMode, anchors, hmSigma, numSParamRows, numFreqPoints, cfg, execEnv);
        yTe = yp(teMask);
        rec = accumUnit(rec, units{u}, yTe, predTe, xyOf, nearInsertMap, '(pooled)');
        nFoldTotal = nFoldTotal + 1;
        fprintf('  [%s %s] unit %d/%d = %s  (%d test pos, %.1fs)\n', ...
            lopoMode, lopoUnit, u, nUnits, unitName{u}, numel(units{u}), toc(t0));
    end
else  % insession
    for s = 1:nSess
        keep = ismember(built{s}.posLabel, validPos);
        Xs = built{s}.X(:, :, :, keep); ys = built{s}.posLabel(keep);
        for u = 1:nUnits
            teMask = ismember(ys, units{u}); if ~any(teMask), continue; end
            t0 = tic;
            trMask = ~teMask; yTr = ys(trMask);
            TTr = labelsToXY(yTr, adjMap);
            [Xt0, Tt0, Xv0, Tv0] = posDisjointSplit(Xs(:, :, :, trMask), TTr, yTr, posValFrac);
            [Xtr_a, Ttr_a] = maybeMixup(Xt0, Tt0, mixAlpha, mixRatio);
            predTe = fitPredictFold(Xtr_a, Ttr_a, Xs(:, :, :, teMask), Xv0, Tv0, ...
                                    headMode, anchors, hmSigma, numSParamRows, numFreqPoints, cfg, execEnv);
            rec = accumUnit(rec, units{u}, ys(teMask), predTe, xyOf, nearInsertMap, sessNames{s});
            nFoldTotal = nFoldTotal + 1;
            if mod(u, 5) == 0 || u == nUnits
                fprintf('  [%s %s] sess %d/%d unit %d/%d  (%.1fs, %.0fs elapsed)\n', ...
                    lopoMode, lopoUnit, s, nSess, u, nUnits, toc(t0), toc(tAll));
            end
        end
