fprintf('LOPO done: %d folds in %.0f s\n', nFoldTotal, toc(tAll));

%% 5. AGGREGATE (error distance only)
errs = [rec.err]; sprs = [rec.spread]; near = logical([rec.near]);
overall = distStats(errs, sprs, HALF);
stratN = distStats(errs(near), sprs(near), HALF);
