% per-session summary (meaningful for insession; single pass for pooled)
usess = unique({rec.sess}, 'stable');
perSession = struct('sess', {}, 'medianErrIn', {}, 'pctWithinHalfIn', {}, 'medianSpreadIn', {}, 'n', {});
for i = 1:numel(usess)
    m = strcmp({rec.sess}, usess{i});
    ss = distStats([rec(m).err], [rec(m).spread], HALF);
    perSession(end+1) = struct('sess', usess{i}, 'medianErrIn', ss.medianErrIn, ...
        'pctWithinHalfIn', ss.pctWithinHalfIn, 'medianSpreadIn', ss.medianSpreadIn, ...
        'n', numel([rec(m).err])); %#ok<SAGROW>
end
