    crossMedErr = [mean([perSession.medianErrIn]), std([perSession.medianErrIn])];
    crossPctHalf = [mean([perSession.pctWithinHalfIn]), std([perSession.pctWithinHalfIn])];
else
    crossMedErr = [overall.medianErrIn, 0]; crossPctHalf = [overall.pctWithinHalfIn, 0];
end

% per-position (average a position's records across contexts)
perPosition = struct('label', {}, 'x', {}, 'y', {}, 'medianErrIn', {}, 'spreadIn', {}, 'nearInsert', {});
for p = 1:nPos
    m = strcmp({rec.label}, validPos{p});
    if ~any(m), continue; end
    perPosition(end+1) = struct('label', validPos{p}, 'x', validXY(p, 1), 'y', validXY(p, 2), ...
        'medianErrIn', mean([rec(m).err]), 'spreadIn', mean([rec(m).spread]), ...
        'nearInsert', logical(nearInsertMap(validPos{p}))); %#ok<SAGROW>
end

fprintf('\n--------------------------------------------------------------\n');
fprintf('  %s / %s   %s [%s]\n', upper(lopoMode), upper(lopoUnit), setupName, setLabel);
fprintf('  LOPO position median err : %.3f in   (mean %.3f)\n', overall.medianErrIn, overall.meanErrIn);
fprintf('  LOPO position <=0.5 in   : %.1f %%   (<=1in %.1f%%)\n', overall.pctWithinHalfIn, overall.pctWithin1In);
fprintf('  median spread            : %.3f in\n', overall.medianSpreadIn);
if stratN.n > 0
    fprintf('  near-insert / exterior   : %.3f / %.3f in median (n=%d/%d)\n', ...
        stratN.medianErrIn, stratE.medianErrIn, stratN.n, stratE.n);
end
if numel(perSession) > 1
    fprintf('  per-session median err   : %.3f +/- %.3f in (across %d sessions)\n', ...
        crossMedErr(1), crossMedErr(2), numel(perSession));
end
fprintf('--------------------------------------------------------------\n');

%% 6. SAVE
result = struct();
result.method = 'CNN-LOPO'; result.task = 'regression_xy_inches';
result.lopoMode = lopoMode; result.lopoUnit = lopoUnit;
result.setup = setupName; result.sessionSet = setLabel;
