% =========================================================================
%  LOCAL FUNCTIONS
% =========================================================================
function rec = accumUnit(rec, unitLabels, yTe, predTe, xyOf, nearMap, sessTag)
% For each position in the held-out unit: median predicted point over its
% trials, error to the true (x,y), and prediction spread. Append to rec.
    for q = 1:numel(unitLabels)
        L = unitLabels{q};
        m = strcmp(yTe, L); if ~any(m), continue; end
        P = predTe(m, :); med = median(P, 1);
        xy = xyOf(L);
        rec(end+1) = struct('label', L, 'sess', sessTag, ...
            'err', norm(med - xy), ...
            'spread', mean(vecnorm(P - med, 2, 2)), ...
            'near', double(nearMap(L))); %#ok<AGROW>
    end
end

function [Xo, To] = maybeMixup(X, T, alpha, ratio)
% Offline mixup for regression. Appends `ratio*N` synthetic samples, each a
% convex blend  l*A + (1-l)*B  of a random training pair, with the SAME blend
% applied to their (x,y) targets. l ~ Beta(alpha,alpha). Train-only; no test
% data is ever touched, so there is no LOPO leakage.
    if alpha <= 0 || ratio <= 0, Xo = X; To = T; return; end
    n = size(X, 4);
    if n < 2, Xo = X; To = T; return; end
    nMix = max(1, round(ratio * n));
    ii = randi(n, nMix, 1); jj = randi(n, nMix, 1);
    if exist('betarnd', 'file'), lam = betarnd(alpha, alpha, nMix, 1);
    else, lam = rand(nMix, 1); end                 % Beta(1,1) fallback
    sz = size(X);
    Xmix = zeros([sz(1), sz(2), 1, nMix], 'like', X);
    Tmix = zeros(nMix, size(T, 2));
    for k = 1:nMix
        l = lam(k);
        Xmix(:, :, 1, k) = l * X(:, :, 1, ii(k)) + (1 - l) * X(:, :, 1, jj(k));
        Tmix(k, :)       = l * T(ii(k), :)       + (1 - l) * T(jj(k), :);
    end
    Xo = cat(4, X, Xmix); To = [T; Tmix];
end

function predTe = fitPredictFold(Xtr, xyTr, Xte, Xval, xyVal, headMode, anchors, hmSigma, nRows, nFreq, cfg, execEnv)
% Train one fold and return predicted (x,y) for the test samples. Dispatches on
% head: 'xy' = fc(2)+regression; 'heatmap' = softmax over anchor grid trained on
% a Gaussian soft target, prediction = distribution centroid.
    if strcmp(headMode, 'heatmap')
        TsoftTr = xyToHeatmap(xyTr, anchors, hmSigma);
        if ~isempty(Xval), TsoftV = xyToHeatmap(xyVal, anchors, hmSigma); else, TsoftV = []; end
        net = trainCNNHeatmap(Xtr, TsoftTr, nRows, nFreq, size(anchors,1), cfg, execEnv, Xval, TsoftV);
        soft = double(predict(net, Xte));        % (Nte x G) softmax over anchors
        predTe = soft * anchors;                 % centroid readout -> (Nte x 2)
    else
        net = trainCNNReg(Xtr, xyTr, nRows, nFreq, cfg, execEnv, Xval, xyVal);
        predTe = double(predict(net, Xte));
    end
end

function P = xyToHeatmap(xy, anchors, sigma)
% Soft target: each sample -> Gaussian over the anchor grid, normalized to a
% probability vector. (N x G)
    n = size(xy, 1); G = size(anchors, 1);
    P = zeros(n, G);
    for i = 1:n
        d2 = sum((anchors - xy(i, :)).^2, 2);
        w = exp(-d2 / (2 * sigma^2));
        s = sum(w); if s <= 0, w = ones(G,1); s = G; end
        P(i, :) = (w / s)';
    end
end

function net = trainCNNHeatmap(XTrain, Tsoft, nRows, nFreq, G, cfg, execEnv, Xval, Tval)
% Same conv trunk as trainCNNReg but head = fc(G) -> softmax -> regression on
% the soft (Gaussian-over-anchors) target.
    if nargin < 8, Xval = []; Tval = []; end
    layers = [
        imageInputLayer([nRows nFreq 1], 'Normalization', 'zscore', 'Name', 'input')
        convolution2dLayer([min(4,nRows) 20], cfg.Conv1, 'Padding', 'same', 'Name', 'conv1')
        batchNormalizationLayer('Name', 'bn1'); reluLayer('Name', 'relu1')
        convolution2dLayer([min(2,nRows) 10], cfg.Conv2, 'Padding', 'same', 'Name', 'conv2')
        batchNormalizationLayer('Name', 'bn2'); reluLayer('Name', 'relu2')
        fullyConnectedLayer(cfg.FC1, 'Name', 'fc1')
        batchNormalizationLayer('Name', 'bn3'); reluLayer('Name', 'relu3')
        dropoutLayer(cfg.Dropout, 'Name', 'dropout')
        fullyConnectedLayer(G, 'Name', 'fc_out')
        softmaxLayer('Name', 'softmax')
        regressionLayer('Name', 'output')];
    if cfg.showPlots, plt = 'training-progress'; else, plt = 'none'; end
    args = {'MaxEpochs', cfg.Epochs, 'MiniBatchSize', cfg.BatchSize, ...
        'InitialLearnRate', cfg.LR, 'LearnRateSchedule', 'piecewise', ...
        'LearnRateDropPeriod', cfg.LRDropPeriod, 'LearnRateDropFactor', cfg.LRDropFactor, ...
        'Shuffle', 'every-epoch', 'ExecutionEnvironment', execEnv, 'Verbose', false, 'Plots', plt};
    if ~isempty(Xval)
        iterPerEpoch = max(1, floor(size(XTrain, 4) / cfg.BatchSize));
        args = [args, {'ValidationData', {Xval, Tval}, 'ValidationFrequency', iterPerEpoch, ...
                       'ValidationPatience', Inf, 'OutputNetwork', 'best-validation'}];
    end
    net = trainNetwork(XTrain, Tsoft, layers, trainingOptions('adam', args{:}));
end

function [Xt, Tt, Xv, Tv] = posDisjointSplit(X, T, labels, frac)
% Split a training set so that a fraction of the POSITIONS (all their trials)
% become a validation set disjoint from training. Model selection on this set
% rewards generalization to unseen positions, not memorized ones.
    Xv = []; Tv = [];
    if frac <= 0, Xt = X; Tt = T; return; end
    u = unique(labels);
    if numel(u) < 3, Xt = X; Tt = T; return; end     % too few to spare
    nv = min(numel(u) - 1, max(1, round(frac * numel(u))));
    p = randperm(numel(u));
    valpos = u(p(1:nv));
    isval = ismember(labels, valpos);
    Xt = X(:, :, :, ~isval); Tt = T(~isval, :);
    Xv = X(:, :, :,  isval); Tv = T( isval, :);
end

function S = distStats(errs, sprs, half)
    if isempty(errs)
        S = struct('n', 0, 'medianErrIn', NaN, 'meanErrIn', NaN, ...
                   'pctWithinHalfIn', NaN, 'pctWithin1In', NaN, 'medianSpreadIn', NaN);
        return;
    end
    S.n = numel(errs);
    S.medianErrIn = median(errs); S.meanErrIn = mean(errs);
    S.pctWithinHalfIn = 100 * mean(errs <= half); S.pctWithin1In = 100 * mean(errs <= 1.0);
    S.medianSpreadIn = median(sprs);
end

function T = labelsToXY(labels, adjMap)
    T = zeros(numel(labels), 2);
    for i = 1:numel(labels), T(i, :) = labelToXY(labels{i}, adjMap); end
end

function xy = labelToXY(lbl, adjMap)
    if isKey(adjMap, lbl), xy = adjMap(lbl); return; end
    tok = regexp(lbl, 'R(\d+)C(\d+)P(\d+)', 'tokens'); t = tok{1};
    r = str2double(t{1}); c = str2double(t{2}); p = str2double(t{3});
    sp = 0.375; off = [-sp -sp; +sp -sp; +sp +sp; -sp +sp];
    xy = [(c - 0.5) + off(p, 1), (r - 0.5) + off(p, 2)];
end

function [sessions, names] = loadAllSessions(parentDir)
    d = dir(parentDir); subs = d([d.isdir] & ~ismember({d.name}, {'.', '..'}));
    filt = strtrim(getenv('CNN_LOSO_SESSIONS'));
    if ~isempty(filt)
        toks = strsplit(filt, {' ', ','}); toks = toks(~cellfun(@isempty, toks));
        keep = false(1, numel(subs));
        for ii = 1:numel(subs)
            for tt = 1:numel(toks)
                if contains(subs(ii).name, toks{tt}), keep(ii) = true; break; end
            end
        end
        subs = subs(keep);
        fprintf('[filter] CNN_LOSO_SESSIONS=%s -> %d folders\n', filt, numel(subs));
    end
    remapStr = strtrim(getenv('CNN_LOSO_PORT_REMAP')); rowperm = [];
    if ~isempty(remapStr)
        R = str2num(remapStr); rowperm = zeros(1, 32); %#ok<ST2NM>
        for a = 1:4, for b = 1:4
            nidx = (b-1)*4 + a; oidx = (R(b)-1)*4 + R(a);
            rowperm(2*nidx-1) = 2*oidx-1; rowperm(2*nidx) = 2*oidx;
        end, end
        fprintf('[remap] CNN_LOSO_PORT_REMAP=%s\n', remapStr);
    end
    sessions = {}; names = {};
    for i = 1:numel(subs)
        p = fullfile(parentDir, subs(i).name);
        if ~isempty(dir(fullfile(p, 'R*C*P*_T*.csv')))
            try
                L = loadHunterVnaFolder(p);
                if ~isempty(rowperm), L = permuteSessionRows(L, rowperm); end
                sessions{end+1} = L; names{end+1} = subs(i).name; %#ok<AGROW>
            catch ME
                fprintf('  SKIP %s (%s)\n', subs(i).name, ME.message);
            end
        end
    end
end

function L = permuteSessionRows(L, rowperm)
    for p = 1:size(L.data, 1)
        for t = 2:size(L.data, 2)
            M = L.data{p, t};
            if ~isempty(M) && size(M, 1) == numel(rowperm), L.data{p, t} = M(rowperm, :); end
        end
    end
    if isfield(L, 'baseline') && size(L.baseline, 1) == numel(rowperm)
        L.baseline = L.baseline(rowperm, :);
    end
    if isfield(L, 'baselineAll') && ~isempty(L.baselineAll) && size(L.baselineAll, 1) == numel(rowperm)
        L.baselineAll = L.baselineAll(rowperm, :, :);
    end
end

function [rows, names, pairs] = antennaRows(ports, reflOnly)
    if nargin < 2, reflOnly = false; end
    rows = []; names = {}; pairs = [];
    for i = ports, for j = ports
        if reflOnly && i ~= j, continue; end
        idx = (j-1)*4 + i;
        rows(end+1) = 2*idx-1; rows(end+1) = 2*idx; %#ok<AGROW>
        names{end+1} = sprintf('S%d%d', i, j); %#ok<AGROW>
        pairs(end+1, :) = [2*idx-1, 2*idx]; %#ok<AGROW>
    end, end
    [rows, ~] = sort(rows); names = unique(names, 'stable');
end

function S = buildSession(loaded, pairs, inputMode, nTdr, meanSub)
    data = loaded.data; baseline = loaded.baseline;
    nPos = size(data, 1); trialCount = loaded.trialCount; nFreq = loaded.numFreqPoints;
    K = size(pairs, 1);
    baseC = zeros(K, nFreq);
    for k = 1:K
        baseC(k, :) = baseline(pairs(k,1), :) .* exp(1j * deg2rad(baseline(pairs(k,2), :)));
    end
    Yall = zeros(K, nFreq, nPos * trialCount); posLabel = cell(nPos * trialCount, 1); n = 0;
    for p = 1:nPos
        lbl = data{p, 1};
        for t = 1:trialCount
            raw = data{p, t+1};
            if isempty(raw) || any(isnan(raw(:))), continue; end
            n = n + 1; Sc = zeros(K, nFreq);
            for k = 1:K
                Sc(k, :) = raw(pairs(k,1), :) .* exp(1j * deg2rad(raw(pairs(k,2), :)));
            end
            Yall(:, :, n) = Sc - baseC; posLabel{n} = lbl;
        end
    end
    Yall = Yall(:, :, 1:n); posLabel = posLabel(1:n);
    if meanSub, Yall = Yall - mean(Yall, 3); end
    switch inputMode
        case 'raw',     nRows = 2 * K; W = nFreq;
        case 'physics', nRows = 5 * K; W = nFreq;
        case 'tdr',     nRows = K;     W = nTdr;
        otherwise, error('unknown CNN_LOSO_INPUT %s', inputMode);
    end
    X = zeros(nRows, W, 1, n);
    for i = 1:n
        block = zeros(nRows, W);
        for k = 1:K
            yv = Yall(k, :, i); env = abs(ifft(yv));
            switch inputMode
                case 'raw',  block((k-1)*2 + (1:2), :) = [abs(yv); angle(yv)];
                case 'tdr',  block(k, :) = env(1:nTdr);
                case 'physics'
                    envpad = zeros(1, nFreq); envpad(1:nTdr) = env(1:nTdr);
                    block((k-1)*5 + (1:5), :) = [abs(yv); angle(yv); real(yv); imag(yv); envpad];
            end
        end
        X(:, :, 1, i) = block;
    end
    if n > 1, X = (X - mean(X, 4)) ./ (std(X, 0, 4) + 1e-8); end
    S.X = X; S.posLabel = posLabel;
end

function net = trainCNNReg(XTrain, TTrain, nRows, nFreq, cfg, execEnv, Xval, Tval)
    if nargin < 8, Xval = []; Tval = []; end
    layers = [
        imageInputLayer([nRows nFreq 1], 'Normalization', 'zscore', 'Name', 'input')
        convolution2dLayer([min(4,nRows) 20], cfg.Conv1, 'Padding', 'same', 'Name', 'conv1')
        batchNormalizationLayer('Name', 'bn1'); reluLayer('Name', 'relu1')
        convolution2dLayer([min(2,nRows) 10], cfg.Conv2, 'Padding', 'same', 'Name', 'conv2')
        batchNormalizationLayer('Name', 'bn2'); reluLayer('Name', 'relu2')
        fullyConnectedLayer(cfg.FC1, 'Name', 'fc1')
        batchNormalizationLayer('Name', 'bn3'); reluLayer('Name', 'relu3')
        dropoutLayer(cfg.Dropout, 'Name', 'dropout')
        fullyConnectedLayer(2, 'Name', 'fc_out')
        regressionLayer('Name', 'output')];
    if cfg.showPlots, plt = 'training-progress'; else, plt = 'none'; end
    args = {'MaxEpochs', cfg.Epochs, 'MiniBatchSize', cfg.BatchSize, ...
        'InitialLearnRate', cfg.LR, 'LearnRateSchedule', 'piecewise', ...
        'LearnRateDropPeriod', cfg.LRDropPeriod, 'LearnRateDropFactor', cfg.LRDropFactor, ...
        'Shuffle', 'every-epoch', 'ExecutionEnvironment', execEnv, 'Verbose', false, 'Plots', plt};
    if ~isempty(Xval)
        % position-disjoint validation: keep the best-validation network, no
        % early stop (isolate model SELECTION, not shortened training).
        iterPerEpoch = max(1, floor(size(XTrain, 4) / cfg.BatchSize));
        args = [args, {'ValidationData', {Xval, Tval}, ...
                       'ValidationFrequency', iterPerEpoch, ...
                       'ValidationPatience', Inf, ...
                       'OutputNetwork', 'best-validation'}];
    end
    opts = trainingOptions('adam', args{:});
    net = trainNetwork(XTrain, TTrain, layers, opts);
end
